"use strict";(self.webpackChunkfedpat_docs=self.webpackChunkfedpat_docs||[]).push([[1319],{5969:(e,n,a)=>{a.r(n),a.d(n,{assets:()=>i,contentTitle:()=>t,default:()=>p,frontMatter:()=>l,metadata:()=>s,toc:()=>c});var o=a(4848),r=a(8453);const l={id:"excel-skill-raw",title:"SKILL.md \u2014 Excel",sidebar_label:"SKILL.md"},t="SKILL.md \u2014 Excel",s={id:"ia/claude-skills/excel-skill-raw",title:"SKILL.md \u2014 Excel",description:"Archivo de instrucciones que Claude usa internamente. Si encontr\xe1s algo para mejorar, abr\xed un PR directamente.",source:"@site/docs/ia/claude-skills/excel-skill-raw.md",sourceDirName:"ia/claude-skills",slug:"/ia/claude-skills/excel-skill-raw",permalink:"/flock-tech-guides/ia/claude-skills/excel-skill-raw",draft:!1,unlisted:!1,editUrl:"https://github.com/Mujics/flock-tech-guides/tree/main/flock-tech-guides/docs/ia/claude-skills/excel-skill-raw.md",tags:[],version:"current",frontMatter:{id:"excel-skill-raw",title:"SKILL.md \u2014 Excel",sidebar_label:"SKILL.md"},sidebar:"docs",previous:{title:"Excel Skill",permalink:"/flock-tech-guides/ia/claude-skills/excel-skill"},next:{title:"PowerPoint Skill",permalink:"/flock-tech-guides/ia/claude-skills/powerpoint-skill"}},i={},c=[];function d(e){const n={a:"a",admonition:"admonition",code:"code",h1:"h1",hr:"hr",p:"p",pre:"pre",...(0,r.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(n.h1,{id:"skillmd--excel",children:"SKILL.md \u2014 Excel"}),"\n",(0,o.jsx)(n.p,{children:"Archivo de instrucciones que Claude usa internamente. Si encontr\xe1s algo para mejorar, abr\xed un PR directamente."}),"\n",(0,o.jsx)(n.admonition,{title:"Contribuir",type:"info",children:(0,o.jsxs)(n.p,{children:[(0,o.jsx)(n.a,{href:"https://github.com/Flock-engineering/flock-tech-guides/edit/dev/static/skills/excel/SKILL.md",children:"\u270f\ufe0f Sugerir correcci\xf3n en GitHub"})," \u2014 GitHub te propone hacer fork y PR autom\xe1ticamente si no ten\xe9s permisos de push."]})}),"\n",(0,o.jsx)(n.p,{children:(0,o.jsx)(n.a,{href:"pathname:///flock-tech-guides/skills/excel/SKILL.md",children:"\u2b07 Descargar SKILL.md"})}),"\n",(0,o.jsx)(n.hr,{}),"\n",(0,o.jsx)(n.pre,{children:(0,o.jsx)(n.code,{className:"language-md",children:'---\nname: excel\ndescription: >\n  Genera planillas Excel (.xlsx) con estilo profesional y compatibilidad con SharePoint y Excel Online.\n  Trigger: crear planilla Excel, generar .xlsx, crear reporte Excel, crear tabla Excel\nargument-hint: "[descripci\xf3n de la planilla]"\nlicense: MIT\nmetadata:\n  author: flock\n  version: \'1.0\'\n  scope: [root]\n  auto_invoke:\n    - \'Crear planilla Excel\'\n    - \'Generar .xlsx\'\n    - \'Crear reporte Excel\'\n    - \'Crear tabla Excel\'\n    - \'Generar planilla\'\nallowed-tools: Bash, Read, Write, Glob\ncontext: fork\n---\n\n# Skill: Generar planilla Excel\n\n## Critical Rules\n\n### ALWAYS\n\n- Usar **`.xlsx`** siempre \u2014 nunca `.xls`, `.xlsm` ni `.xlsb`\n- Mostrar el outline al usuario y esperar confirmaci\xf3n antes de generar\n- Usar `python3`, nunca `python`\n- Guardar el script temporal siempre en `/tmp/`\n- Eliminar el script temporal despu\xe9s de ejecutarlo\n- Usar **`Table` nativo de openpyxl** para tablas \u2014 garantiza compatibilidad con SharePoint y Excel Online\n- Aplicar `freeze_panes` en la fila de headers\n- Page setup A4 por defecto\n- Autofit de columnas siempre\n\n### NEVER\n\n- Continuar al paso 5 sin confirmaci\xf3n expl\xedcita del paso 4\n- Guardar scripts temporales en el directorio del proyecto\n- Usar macros, VBA ni f\xf3rmulas con conexiones externas \u2014 no compatibles en SharePoint\n- Usar `WidthType.PERCENTAGE` ni anchos relativos \u2014 usar ancho fijo en caracteres\n- Usar fuentes no est\xe1ndar \u2014 solo Calibri o Arial (Excel Online no soporta fuentes embebidas)\n- Usar charts 3D \u2014 no renderizan correctamente en Excel Online\n- Usar `python` en vez de `python3`\n\n---\n\n## SharePoint / Excel Online \u2014 Compatibilidad\n\n| Feature | Soporte | Nota |\n|---|---|---|\n| `.xlsx` | \u2705 Completo | \xdanico formato recomendado |\n| Tablas nativas (`Table`) | \u2705 Completo | Usar siempre para rangos de datos |\n| Freeze panes | \u2705 Completo | Funciona en Excel Online |\n| Conditional formatting | \u2705 Completo | Soportado |\n| Named ranges | \u2705 Completo | Soportado |\n| Charts b\xe1sicos (bar, line, pie) | \u2705 Mayormente | Evitar 3D |\n| Im\xe1genes | \u26a0\ufe0f Parcial | Funciona pero puede variar en Online |\n| Macros / VBA | \u274c No | Bloqueado en SharePoint por seguridad |\n| Conexiones externas | \u274c No | No soportado en Online |\n| Fuentes embebidas | \u274c No | Usar Calibri o Arial |\n\n---\n\n## 1. Verificar openpyxl\n\n```bash\npython3 -c "import openpyxl" 2>/dev/null && echo "OK" || pip3 install openpyxl -q\n```\n\n## 2. Entender la planilla\n\nAnaliz\xe1 `$ARGUMENTS`:\n\n- Si hay descripci\xf3n suficiente \u2192 continu\xe1\n- Si es vago o vac\xedo \u2192 pregunt\xe1: nombre de la planilla, hojas necesarias, columnas, tipo de datos (texto, n\xfamero, fecha, moneda), si necesita f\xf3rmulas\n- Si el usuario menciona archivos de datos (CSV, JSON, Excel) \u2192 le\xe9los con Read/Glob **antes** de continuar\n\n## 3. Confirmar estructura antes de generar\n\nMostr\xe1 el outline al usuario y esper\xe1 confirmaci\xf3n expl\xedcita:\n\n```\n\ud83d\udcca Voy a generar: nombre_planilla.xlsx\n\nHojas:\n  - Hoja "Datos": tabla con columnas [A, B, C] \u2014 N filas\n  - Hoja "Resumen": tabla pivot con totales por [X]\n\nConfiguraci\xf3n:\n  - Page size: A4 landscape\n  - Headers congelados: s\xed\n  - Formato de moneda: $ ARS\n\n\xbfConfirm\xe1s? (s/n)\n```\n\nNo contin\xfaes sin respuesta afirmativa.\n\n## 4. Generar el script Python\n\nEscrib\xed el script en `/tmp/gen_excel.py`. Aplic\xe1 **siempre** la gu\xeda de estilos completa:\n\n```python\nimport os\nfrom openpyxl import Workbook\nfrom openpyxl.styles import Font, PatternFill, Alignment, Border, Side\nfrom openpyxl.utils import get_column_letter\nfrom openpyxl.worksheet.table import Table, TableStyleInfo\nfrom openpyxl.worksheet.page import PageMargins\n\n# \u2500\u2500 PALETA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nCOLOR_HEADER  = "1F497D"  # azul corporativo \u2014 header de tablas\nCOLOR_SUBHDR  = "2E74B5"  # azul claro \u2014 subheaders\nCOLOR_ROW_ALT = "DCE6F1"  # azul muy claro \u2014 filas alternadas\nCOLOR_WHITE   = "FFFFFF"\nCOLOR_TEXT    = "262626"  # casi negro\n\n# \u2500\u2500 TIPOGRAF\xcdA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nFONT_NAME  = "Calibri"\nSIZE_BODY  = 11\nSIZE_HDR   = 11\nSIZE_TITLE = 16\n\n# \u2500\u2500 ESTILOS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef hdr_font(size=SIZE_HDR, color=COLOR_WHITE):\n    return Font(name=FONT_NAME, bold=True, size=size, color=color)\n\ndef body_font(bold=False, size=SIZE_BODY, color=COLOR_TEXT):\n    return Font(name=FONT_NAME, bold=bold, size=size, color=color)\n\ndef fill(hex_color):\n    return PatternFill(fill_type="solid", fgColor=hex_color)\n\ndef align(horizontal="left", wrap=True):\n    return Alignment(horizontal=horizontal, vertical="center", wrap_text=wrap)\n\ndef thin_border():\n    s = Side(style="thin", color="BFBFBF")\n    return Border(left=s, right=s, top=s, bottom=s)\n\n# \u2500\u2500 TABLA ESTILIZADA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# \u26a0\ufe0f  Usar siempre Table nativo \u2014 compatible con SharePoint y Excel Online.\n#     No usar anchos de columna en porcentaje \u2014 usar ancho fijo en caracteres.\ndef add_styled_table(ws, headers, rows, start_row=1, start_col=1, table_name="Tabla1"):\n    # Header\n    for ci, h in enumerate(headers, start=start_col):\n        c = ws.cell(row=start_row, column=ci, value=h)\n        c.font      = hdr_font()\n        c.fill      = fill(COLOR_HEADER)\n        c.alignment = align("center")\n        c.border    = thin_border()\n\n    # Rows\n    for ri, row_data in enumerate(rows, start=start_row + 1):\n        row_color = COLOR_ROW_ALT if (ri - start_row) % 2 == 0 else COLOR_WHITE\n        for ci, value in enumerate(row_data, start=start_col):\n            c = ws.cell(row=ri, column=ci, value=value)\n            c.font      = body_font()\n            c.fill      = fill(row_color)\n            c.alignment = align("left")\n            c.border    = thin_border()\n\n    # Registrar como Table nativo (requerido para SharePoint / Excel Online)\n    end_row = start_row + len(rows)\n    end_col = start_col + len(headers) - 1\n    ref     = f"{get_column_letter(start_col)}{start_row}:{get_column_letter(end_col)}{end_row}"\n    tbl     = Table(displayName=table_name, ref=ref)\n    tbl.tableStyleInfo = TableStyleInfo(\n        name="TableStyleMedium2",\n        showRowStripes=True,\n        showColumnStripes=False,\n    )\n    ws.add_table(tbl)\n    return tbl\n\n# \u2500\u2500 T\xcdTULO DE HOJA \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef add_sheet_title(ws, title, row=1, col=1):\n    c = ws.cell(row=row, column=col, value=title)\n    c.font      = Font(name=FONT_NAME, bold=True, size=SIZE_TITLE, color=COLOR_HEADER)\n    c.alignment = align("left", wrap=False)\n    ws.row_dimensions[row].height = 28\n\n# \u2500\u2500 PAGE SETUP \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef setup_page(ws, landscape=True):\n    """A4 por defecto \u2014 compatible con print preview en SharePoint"""\n    ws.page_setup.paperSize   = ws.PAPERSIZE_A4\n    ws.page_setup.orientation = ws.ORIENTATION_LANDSCAPE if landscape else ws.ORIENTATION_PORTRAIT\n    ws.page_margins           = PageMargins(left=0.75, right=0.75, top=1.0, bottom=1.0)\n    ws.page_setup.fitToPage   = True\n    ws.page_setup.fitToWidth  = 1\n    ws.page_setup.fitToHeight = 0\n\n# \u2500\u2500 FREEZE PANES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef freeze_header(ws, freeze_row=2, freeze_col=1):\n    """Congela headers \u2014 funciona en SharePoint y Excel Online"""\n    ws.freeze_panes = ws.cell(row=freeze_row, column=freeze_col)\n\n# \u2500\u2500 AUTOFIT COLUMNAS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef autofit_columns(ws, min_width=10, max_width=40):\n    for col in ws.columns:\n        max_len = max((len(str(cell.value or "")) for cell in col), default=0)\n        ws.column_dimensions[col[0].column_letter].width = max(min_width, min(max_len + 2, max_width))\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PLANILLA (adaptar a partir de aqu\xed seg\xfan la solicitud del usuario)\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nwb = Workbook()\nws = wb.active\nws.title = "Datos"\n\nsetup_page(ws)\nfreeze_header(ws)\n\n# --- contenido de la planilla ---\n\nautofit_columns(ws)\n\noutput_path = "planilla.xlsx"\nwb.save(output_path)\nprint(f"\u2713 {os.path.abspath(output_path)}")\n```\n\n## 5. Ejecutar y limpiar\n\n```bash\npython3 /tmp/gen_excel.py && rm /tmp/gen_excel.py\n```\n\nVerific\xe1 que el archivo fue creado:\n\n```bash\nls -lh planilla.xlsx\n```\n\n## 6. Informar al usuario\n\nRespond\xe9 con:\n- Ruta absoluta del archivo generado y su tama\xf1o\n- Resumen de la estructura (hojas, tablas, filas, f\xf3rmulas)\n- Confirmaci\xf3n de que el script temporal fue eliminado\n\n---\n\n## Professional Spreadsheet Base\n\nEsqueleto m\xednimo recomendado \u2014 punto de partida copy-paste para cualquier planilla:\n\n```python\nwb = Workbook()\nws = wb.active\nws.title = "Datos"\n\n# Page setup: A4 landscape (default para reportes)\nsetup_page(ws, landscape=True)\n# Portrait para planillas verticales largas:\n# setup_page(ws, landscape=False)\n\n# T\xedtulo de la hoja\nadd_sheet_title(ws, title="T\xedtulo del Reporte", row=1)\n\n# Tabla de datos (empieza en fila 2 para dejar espacio al t\xedtulo)\nheaders = ["Columna A", "Columna B", "Columna C"]\nrows    = [\n    ["Valor 1", 100, "2026-03-10"],\n    ["Valor 2", 200, "2026-03-11"],\n]\nadd_styled_table(ws, headers, rows, start_row=2, table_name="TablaReporte")\n\n# Congelar headers (fila 2 = encabezado de la tabla)\nfreeze_header(ws, freeze_row=3)\n\n# Autofit al final, despu\xe9s de cargar todos los datos\nautofit_columns(ws)\n\nwb.save("reporte.xlsx")\nprint(f"\u2713 {os.path.abspath(\'reporte.xlsx\')}")\n```\n\n---\n\n## Formatos de Celda Comunes\n\n```python\nfrom openpyxl.styles import numbers\n\n# Moneda ARS\ncell.number_format = \'"$"#,##0.00\'\n\n# Moneda USD\ncell.number_format = \'"USD "#,##0.00\'\n\n# Porcentaje\ncell.number_format = \'0.00%\'\n\n# Fecha\ncell.number_format = \'DD/MM/YYYY\'\n\n# N\xfamero con separador de miles\ncell.number_format = \'#,##0\'\n```\n\n---\n\n## M\xfaltiples Hojas\n\n```python\nwb = Workbook()\n\n# Hoja 1 \u2014 datos\nws_data = wb.active\nws_data.title = "Datos"\nsetup_page(ws_data)\n\n# Hoja 2 \u2014 resumen\nws_summary = wb.create_sheet(title="Resumen")\nsetup_page(ws_summary)\n\n# Hoja de \xedndice \u2014 siempre primera\nws_index = wb.create_sheet(title="\xcdndice", index=0)\n```\n\n---\n\n## Notas\n\n- Siempre us\xe1 `python3`, nunca `python`\n- El script temporal va **siempre en `/tmp/`**, nunca en el directorio del proyecto\n- Si hay datos externos (CSV, JSON), le\xe9los con Read/Glob **antes** de escribir el script\n- Guardar siempre como `.xlsx` \u2014 es el \xfanico formato compatible con SharePoint sin restricciones\n- Los `table_name` en `Table` deben ser \xfanicos por workbook y sin espacios\n- `autofit_columns` llamarlo **siempre al final**, despu\xe9s de cargar todos los datos\n- Freeze panes: `freeze_row` debe apuntar a la **primera fila de datos**, no al header\n- No contin\xfaes al paso 4 sin confirmaci\xf3n expl\xedcita del paso 3\n'})})]})}function p(e={}){const{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,o.jsx)(n,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},8453:(e,n,a)=>{a.d(n,{R:()=>t,x:()=>s});var o=a(6540);const r={},l=o.createContext(r);function t(e){const n=o.useContext(l);return o.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function s(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:t(e.components),o.createElement(l.Provider,{value:n},e.children)}}}]);